import { resolveHubFrameProfile } from './hubFrameLayout';
import type { HubLayoutMode } from './hubSettingsStore';

function getHubIframe(): HTMLIFrameElement | null {
  const el = window.frameElement;
  return el instanceof HTMLIFrameElement ? el : null;
}

function applyIframeFrameStyles(
  iframe: HTMLIFrameElement,
  styles: {
    width: string;
    height: string;
    maxWidth: string;
    maxHeight: string;
    aspectRatio: string;
    minHeight: string;
  },
) {
  iframe.style.display = 'block';
  iframe.style.marginInline = 'auto';
  iframe.style.border = '0';
  iframe.style.background = 'transparent';
  iframe.style.width = styles.width;
  iframe.style.height = styles.height;
  iframe.style.maxWidth = styles.maxWidth;
  iframe.style.maxHeight = styles.maxHeight;
  iframe.style.aspectRatio = styles.aspectRatio;
  iframe.style.minHeight = styles.minHeight;

  const wrapper = iframe.closest('.mes_streaming');
  if (wrapper instanceof HTMLElement) {
    wrapper.style.width = '100%';
    wrapper.style.minHeight = styles.minHeight;
    wrapper.style.height = styles.height === '100vh' ? '100vh' : '';
  }
}

/** 将当前布局对应的外框尺寸同步到酒馆第 0 楼 iframe 与外层容器 */
export function syncHubFrameSize(layout: HubLayoutMode) {
  const profile = resolveHubFrameProfile(layout);
  const min_height = `min(calc(92vw * ${profile.maxHeight} / ${profile.maxWidth}), ${profile.maxHeight}px)`;

  const iframe = getHubIframe();
  if (!iframe) return;

  applyIframeFrameStyles(iframe, {
    width: '100%',
    height: '',
    maxWidth: `${profile.maxWidth}px`,
    maxHeight: `${profile.maxHeight}px`,
    aspectRatio: profile.aspectRatio,
    minHeight: min_height,
  });
}

/** 全屏时让 iframe 占满可视区域 */
export function syncHubFrameFullscreen(fill: boolean, layout: HubLayoutMode = 'desktop') {
  const iframe = getHubIframe();
  if (!iframe) return;

  if (!fill) {
    syncHubFrameSize(layout);
    return;
  }

  applyIframeFrameStyles(iframe, {
    width: '100vw',
    height: '100vh',
    maxWidth: '100vw',
    maxHeight: '100vh',
    aspectRatio: 'unset',
    minHeight: '100vh',
  });
}
