index: 15;\n  pointer-events: auto;\n  background: transparent;\n  font-size: calc(14px * var(--hub-font-scale, 1));\n}\n\n.input-bar__label {\n  display: flex;\n  justify-content: space-between;\n  align-items: center;\n  margin-bottom: 8px;\n  font-size: 12px;\n  font-weight: 700;\n  color: #0284c7;\n  letter-spacing: 0.08em;\n  text-transform: uppercase;\n}\n\n.input-bar__status {\n  color: #64748b;\n  font-weight: 500;\n  text-transform: none;\n  letter-spacing: 0;\n}\n\n.input-bar__options-pop {\n  position: absolute;\n  right: 0;\n  bottom: calc(100% - 4px);\n  width: min(100%, 320px);\n  max-height: min(40vh, 220px);\n  overflow-y: auto;\n  display: flex;\n  flex-direction: column;\n  gap: 6px;\n  padding: 10px;\n  border-radius: 12px 12px 4px 12px;\n  border: 1px solid #bae6fd;\n  background: rgba(255, 255, 255, 0.98);\n  box-shadow: 0 -8px 24px rgba(15, 23, 42, 0.14);\n  z-index: 20;\n  box-sizing: border-box;\n}\n\n.input-bar__option {\n  text-align: left;\n  padding: 10px 12px;\n  border-radius: 8px;\n  border: 1px solid #cbd5e1;\n  background: #f8fafc;\n  cursor: pointer;\n  transition: 0.2s ease;\n\n  &:hover:not(:disabled) {\n    border-color: #38bdf8;\n    background: #e0f2fe;\n  }\n\n  &:disabled {\n    opacity: 0.6;\n    cursor: not-allowed;\n  }\n}\n\n.options-pop-enter-active,\n.options-pop-leave-active {\n  transition:\n    opacity 0.2s ease,\n    transform 0.22s ease;\n}\n\n.options-pop-enter-from,\n.options-pop-leave-to {\n  opacity: 0;\n  transform: translateY(10px);\n}\n\n.input-bar__row {\n  display: flex;\n  align-items: center;\n  gap: 8px;\n}\n\n.input-bar__xiaoai {\n  flex-shrink: 0;\n  width: 40px;\n  height: 40px;\n  padding: 0;\n  border: 2px solid rgba(255, 255, 255, 0.55);\n  border-radius: 50%;\n  background: rgba(255, 255, 255, 0.55);\n  backdrop-filter: blur(4px);\n  cursor: pointer;\n  overflow: hidden;\n  box-shadow: 0 2px 8px rgba(0, 0, 0, 0.12);\n  transition:\n    transform 0.2s ease,\n    box-shadow 0.2s ease;\n\n  img {\n    width: 100%;\n    height: 100%;\n    object-fit: cover;\n    display: block;\n  }\n\n  &:hover {\n    transform: scale(1.05);\n  }\n\n  &--active {\n    box-shadow: 0 0 0 2px #38bdf8, 0 2px 8px rgba(0, 0, 0, 0.12);\n  }\n}\n\n.input-bar__input {\n  flex: 1;\n  min-width: 0;\n  padding: 12px;\n  border-radius: 10px;\n  border: 1px solid rgba(203, 213, 225, 0.85);\n  background: rgba(255, 255, 255, 0.45);\n  backdrop-filter: blur(4px);\n  outline: none;\n  pointer-events: auto;\n\n  &:focus {\n    border-color: #38bdf8;\n    background: rgba(255, 255, 255, 0.62);\n    box-shadow: 0 0 0 3px rgba(56, 189, 248, 0.15);\n  }\n}\n\n.input-bar__btn {\n  flex-shrink: 0;\n  min-width: 44px;\n  height: 40px;\n  padding: 0 14px;\n  border-radius: 10px;\n  border: 1px solid rgba(203, 213, 225, 0.85);\n  background: rgba(226, 232, 240, 0.72);\n  backdrop-filter: blur(4px);\n  font-weight: 700;\n  cursor: pointer;\n  pointer-events: auto;\n\n  &--send {\n    background: linear-gradient(90deg, #0369a1, #0e7490);\n    border: none;\n    color: #fff;\n  }\n\n  &:disabled {\n    opacity: 0.55;\n    cursor: not-allowed;\n  }\n}\n\n.input-bar__options-toggle {\n  position: relative;\n  flex-shrink: 0;\n  width: 40px;\n  height: 40px;\n  padding: 0;\n  border-radius: 10px;\n  border: 1px solid rgba(186, 230, 253, 0.9);\n  background: rgba(240, 249, 255, 0.55);\n  backdrop-filter: blur(4px);\n  color: #0369a1;\n  cursor: pointer;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  transition:\n    background 0.2s ease,\n    transform 0.2s ease;\n\n  &:hover:not(:disabled) {\n    background: #bae6fd;\n  }\n\n  &:disabled {\n    opacity: 0.45;\n    cursor: not-allowed;\n  }\n\n  &--open {\n    background: #0369a1;\n    border-color: #0369a1;\n    color: #fff;\n\n    .input-bar__options-toggle-icon {\n      transform: rotate(180deg);\n    }\n  }\n}\n\n.input-bar__options-toggle-icon {\n  display: block;\n  font-size: 14px;\n  line-height: 1;\n  transition: transform 0.22s ease;\n}\n\n.input-bar__options-badge {\n  position: absolute;\n  top: -5px;\n  right: -5px;\n  min-width: 16px;\n  height: 16px;\n  padding: 0 4px;\n  border-radius: 999px;\n  background: #f97316;\n  color: #fff;\n  font-size: 10px;\n  font-weight: 700;\n  line-height: 16px;\n  text-align: center;\n  box-shadow: 0 1px 4px rgba(0, 0, 0, 0.2);\n}\n"],"sourceRoot":""}]);
